safe_example:
private static final Set<String> ALLOWED_HOSTS = Set.of("api.example.com", "cdn.example.com");

String target = request.getParameter("url");
URL url = new URL(target);
if (!ALLOWED_HOSTS.contains(url.getHost())) {
    throw new SecurityException("Host not allowed: " + url.getHost());
}
InetAddress addr = InetAddress.getByName(url.getHost());
if (addr.isSiteLocalAddress() || addr.isLoopbackAddress() || addr.isLinkLocalAddress()) {
    throw new SecurityException("Requests to private IPs are blocked");
}
InputStream in = url.openStream();
